 1→package dev.tuist.gradle
 2→
 3→import java.net.HttpURLConnection
 4→import java.net.URI
 5→
 6→class TokenExpiredException : Exception()
 7→
 8→class TuistHttpClient(
 9→    private val configurationProvider: ConfigurationProvider,
10→    private val connectTimeoutMs: Int = 30_000,
11→    private val readTimeoutMs: Int = 60_000
12→) {
13→    @Volatile
14→    private var cachedConfig: TuistCacheConfiguration? = null
15→
16→    private val configLock = Any()
17→
18→    fun openConnection(url: URI, config: TuistCacheConfiguration): HttpURLConnection {
19→        val connection = url.toURL().openConnection() as HttpURLConnection
20→        connection.connectTimeout = connectTimeoutMs
21→        connection.readTimeout = readTimeoutMs
22→        connection.setRequestProperty("Authorization", "Bearer ${config.token}")
23→        return connection
24→    }
25→
26→    fun <T> execute(operation: (TuistCacheConfiguration) -> T): T {
27→        val config = getOrFetchConfig()
28→
29→        return try {
30→            operation(config)
31→        } catch (e: TokenExpiredException) {
32→            val refreshedConfig = synchronized(configLock) {
33→                val currentConfig = cachedConfig
34→                if (currentConfig != null && currentConfig !== config) {
35→                    currentConfig
36→                } else {
37→                    cachedConfig = null
38→                    val newConfig = configurationProvider.getConfiguration(forceRefresh = true)
39→                    cachedConfig = newConfig
40→                    newConfig
41→                }
42→            }
43→            operation(refreshedConfig)
44→        }
45→    }
46→
47→    private fun getOrFetchConfig(): TuistCacheConfiguration {
48→        cachedConfig?.let { return it }
49→
50→        synchronized(configLock) {
51→            cachedConfig?.let { return it }
52→            val newConfig = configurationProvider.getConfiguration()
53→            cachedConfig = newConfig
54→            return newConfig
55→        }
56→    }
57→}
